// Register.jsx - With language support
import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LanguageContext } from '../App';
import { LogoFull } from '../components/Logo';
import s from './Auth.module.css';

export default function Register() {
  const nav = useNavigate();
  const { register } = useAuth();
  const { t } = useContext(LanguageContext);
  const [form, setForm] = useState({ username: '', email: '', password: '', confirm: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async e => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirm) return setError(t.passwordMismatch || 'Les mots de passe ne correspondent pas.');
    if (form.password.length < 6) return setError(t.passwordShort || 'Mot de passe trop court (min 6 caractères).');
    setLoading(true);
    try {
      await register(form.username, form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || (t.registerError || "Erreur lors de l'inscription."));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <button onClick={() => nav('/')} className={s.back}>← {t.home || 'Accueil'}</button>
      <div className={s.card}>
        <div className={s.cardLogo}><LogoFull size={32} /></div>
        <h1 className={s.title}>{t.createAccount || 'Créer un compte'}</h1>
        <p className={s.sub}>{t.joinUs || 'Rejoignez AWAL GPT et commencez à chatter'}</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}>
            <label className={s.label}>{t.username || 'Nom d\'utilisateur'}</label>
            <input className={s.input} type="text" placeholder={t.username || 'Votre nom'} value={form.username} onChange={e => setForm({ ...form, username: e.target.value })} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>{t.email || 'Email'}</label>
            <input className={s.input} type="email" placeholder="vous@exemple.com" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>{t.password || 'Mot de passe'}</label>
            <input className={s.input} type="password" placeholder={t.passwordMin || 'Min. 6 caractères'} value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required />
          </div>
          <div className={s.field}>
            <label className={s.label}>{t.confirmPassword || 'Confirmer'}</label>
            <input className={s.input} type="password" placeholder="••••••••" value={form.confirm} onChange={e => setForm({ ...form, confirm: e.target.value })} required />
          </div>
          <button className={s.submit} disabled={loading}>{loading ? 'Création...' : (t.signUp || 'Créer mon compte →')}</button>
        </form>
        <p className={s.switch}>{t.hasAccount || 'Déjà un compte ?'} <Link to="/login" className={s.link}>{t.login || 'Se connecter'}</Link></p>
      </div>
    </div>
  );
}s
